mapper.select:
SELECT id, table_name, operation_type, record_id,
old_value, new_value, operated_by, operated_at, log_date
FROM audit_log
WHERE 1=1

    AND table_name = #{tableName}


    AND operation_type = #{operationType}


    AND log_date >= #{startDate}


    AND log_date <= #{endDate}


    AND operated_by = #{operatedBy}

ORDER BY operated_at DESC
